insert into public.careers (slug, title, riasec_tag, summary, work_environment, typical_tools, day_in_life) values
  ('accountant', 'Accountant', 'CEI', 'Prepares financial statements, manages taxes, and audits business records.', 'Accounting firms, corporations, and government offices', array['Spreadsheets', 'Accounting software', 'BIR e-filing systems']::text[], 'You spend the morning reconciling last month''s ledgers and chasing two missing receipts. After lunch you prepare a client''s quarterly tax filing, double-check every figure, and end the day walking the owner through what the numbers mean for her growing bakery.'),
  ('agriculturist', 'Agriculturist', 'RIE', 'Applies science to improve crop yields, livestock, and farm sustainability.', 'Farms, research stations, and agri-business firms', array['Soil test kits', 'Drones and sensors', 'Farm management software']::text[], 'You are in the rice paddies by sunrise measuring soil moisture ahead of the dry season. Midday is spent training a farmers'' cooperative on a new seed variety, and you end the day analyzing drone imagery that shows exactly which paddocks need attention.'),
  ('architect', 'Architect', 'AIR', 'Designs functional, safe, and beautiful buildings and spaces.', 'Design studios and construction sites', array['CAD and BIM software', 'Sketchbooks', 'Material samples']::text[], 'The morning is spent refining a house design in 3D after the client asked for more natural light. In the afternoon you visit the site, check that the contractor followed your window details, and sketch a revision right on the plywood wall.'),
  ('civil-engineer', 'Civil Engineer', 'RIC', 'Designs and supervises the construction of roads, bridges, buildings, and flood-control systems.', 'Design offices and active construction sites', array['AutoCAD', 'Structural analysis software', 'Survey instruments']::text[], 'Morning starts on site in a hardhat checking rebar spacing against your structural plans. After lunch you are back in the office running load calculations and updating the project engineer on whether the pour can proceed before the rains come.'),
  ('elementary-teacher', 'Elementary School Teacher', 'SAE', 'Teaches and shapes young learners across core subjects in their formative years.', 'Public and private elementary schools', array['Lesson plans', 'Visual aids', 'Learning management apps']::text[], 'You are at school by 6:30 AM arranging the classroom before thirty Grade 3 pupils arrive. The day moves through reading, math games, and a science experiment with plenty of laughter — after dismissal you check papers and prepare tomorrow''s materials.'),
  ('entrepreneur', 'Entrepreneur', 'EAS', 'Builds and grows a business venture, from sari-sari scale to startup.', 'Anywhere the market is — shops, online, co-working spaces', array['Business plans', 'E-commerce platforms', 'Bookkeeping apps']::text[], 'Your morning starts packing orders from last night''s online sales. By noon you are pitching your product to a local grocery chain, and in the evening you review the week''s numbers and decide it is finally time to hire your first employee.'),
  ('guidance-counselor', 'Guidance Counselor', 'SIA', 'Supports students'' academic, career, and personal development in schools.', 'Elementary, secondary, and tertiary schools', array['Assessment tools', 'Counseling frameworks', 'Student records systems']::text[], 'Your morning is one-on-one sessions with students weighing college choices. At noon you run a career orientation for Grade 12, and in the afternoon you sit with a struggling student and their parents, helping the family listen to each other — the part of the job that matters most.'),
  ('hotel-manager', 'Hotel and Restaurant Manager', 'ESC', 'Runs the daily operations of hotels, resorts, and food businesses.', 'Hotels, resorts, and restaurants', array['Property management systems', 'Rosters and inventory sheets', 'POS systems']::text[], 'You walk the lobby at 7 AM checking last night''s occupancy and today''s arrivals. The day is a rhythm of briefings, a supplier negotiation over banquet pricing, and a guest complaint you turn into a glowing review by evening.'),
  ('it-support-specialist', 'IT Support Specialist', 'ICR', 'Keeps an organization''s networks, systems, and devices running smoothly.', 'Corporate offices, BPO firms, and service desks', array['Ticketing systems', 'Remote desktop tools', 'Network diagnostics']::text[], 'Your queue starts with a locked account and a printer that will not print. By mid-morning you are imaging laptops for new hires, and in the afternoon you trace a network slowdown to a failing switch and coordinate the replacement before the night shift logs in.'),
  ('multimedia-artist', 'Multimedia Artist', 'AES', 'Creates visual content — graphics, animation, and video — for brands and media.', 'Studios, agencies, or freelance from home', array['Adobe Creative Suite', 'Drawing tablets', 'Video editing rigs']::text[], 'You start with client feedback on yesterday''s storyboard, adjust the color script, and animate a 15-second sequence by mid-afternoon. Before logging off you post a personal illustration online — your portfolio is your résumé, and it grew again today.'),
  ('police-officer', 'Police Officer', 'RSE', 'Maintains public order, enforces the law, and serves communities.', 'Police stations and field assignments', array['Two-way radios', 'Incident reports', 'Patrol vehicles']::text[], 'Formation at 5:30 AM, then a morning patrol through the public market where vendors know you by name. The afternoon brings a traffic incident to document and a barangay dispute to mediate — the badge is heaviest in the small, human moments.'),
  ('registered-nurse', 'Registered Nurse', 'SIA', 'Provides direct patient care, health education, and treatment support in hospitals and communities.', 'Hospitals, clinics, and community health centers', array['Stethoscope', 'IV and medication kits', 'Electronic patient charts']::text[], 'Your shift starts at 6 AM with endorsement from the night nurse. Through the day you take vitals, administer medications, and update charts — and between rounds you calm a nervous patient''s family, switching easily between Filipino and English.'),
  ('software-developer', 'Software Developer', 'IRC', 'Builds and maintains applications, from mobile apps to enterprise systems.', 'Offices, tech hubs, or fully remote', array['VS Code', 'Git and GitHub', 'Issue trackers']::text[], 'You start by reviewing a teammate''s code over coffee, then spend a deep-focus block building a new feature. In the afternoon stand-up you demo it, fix a bug the tester found, and push your work — all without leaving your home office in Pampanga.');
insert into public.courses (slug, name, degree_type, field, riasec_tag, overview, core_subjects, pros, cons) values
  ('bs-accountancy', 'BS in Accountancy', 'Bachelor', 'Business', 'CEI', 'Trains students in financial reporting, auditing, and taxation toward the CPA licensure exam.', array['Financial Accounting', 'Auditing and Assurance', 'Taxation', 'Cost Accounting', 'Accounting Information Systems']::text[], array['Prestigious CPA track', 'Every business needs accountants', 'Stable and well-compensated profession']::text[], array['Very demanding board exam', 'Heavy workload during study and busy season', 'Detail-heavy routine work']::text[]),
  ('bs-agriculture', 'BS in Agriculture', 'Bachelor', 'Agriculture', 'RIE', 'Covers crop science, animal production, and agribusiness — vital in Central Luzon''s farm economy.', array['Crop Science', 'Animal Science', 'Soil Science', 'Agricultural Economics', 'Farm Mechanization']::text[], array['Central Luzon is the country''s rice bowl', 'Government support and scholarships', 'Agri-tech is modernizing fast']::text[], array['Field work in all weather', 'Farm incomes fluctuate', 'Undervalued despite importance']::text[]),
  ('bs-architecture', 'BS in Architecture', 'Bachelor', 'Design', 'AIR', 'Combines art and engineering to design buildings and spaces, leading to architectural licensure.', array['Architectural Design', 'Building Technology', 'History of Architecture', 'Structural Concepts', 'Urban Planning']::text[], array['Creative work with lasting physical output', 'Licensed profession', 'Growing construction sector']::text[], array['Five-year program plus apprenticeship', 'Studio culture means long nights', 'Licensure exam required']::text[]),
  ('bs-business-administration', 'BS in Business Administration', 'Bachelor', 'Business', 'ECS', 'Develops general management, marketing, and operations skills for corporate or entrepreneurial paths.', array['Principles of Management', 'Marketing Management', 'Business Finance', 'Human Resource Management', 'Operations Management']::text[], array['Versatile degree across industries', 'Good springboard for entrepreneurship', 'Strong local job market']::text[], array['Broad rather than specialized', 'Competitive entry-level market', 'Advancement often requires further study']::text[]),
  ('bs-civil-engineering', 'BS in Civil Engineering', 'Bachelor', 'Engineering', 'RIC', 'Covers the design, construction, and maintenance of infrastructure such as roads, bridges, and buildings.', array['Engineering Mechanics', 'Structural Analysis', 'Hydraulics', 'Geotechnical Engineering', 'Construction Management']::text[], array['Strong job market driven by infrastructure projects', 'Licensed profession with clear career ladder', 'Tangible results you can point to']::text[], array['Heavy math and physics load', 'Licensure exam required', 'Site work can mean long field hours']::text[]),
  ('bs-computer-science', 'BS in Computer Science', 'Bachelor', 'Computing', 'IRC', 'Focuses on programming, algorithms, and the theory behind software systems.', array['Data Structures and Algorithms', 'Discrete Mathematics', 'Operating Systems', 'Software Engineering', 'Machine Learning Basics']::text[], array['High-paying and remote-friendly career paths', 'No licensure exam required', 'Constantly evolving and creative problem solving']::text[], array['Requires sustained self-study', 'Can be sedentary', 'Fast-changing tools demand lifelong learning']::text[]),
  ('bs-criminology', 'BS in Criminology', 'Bachelor', 'Public Safety', 'RSE', 'Studies crime, justice administration, and law enforcement toward the criminologist licensure exam.', array['Criminal Law', 'Criminalistics', 'Law Enforcement Administration', 'Forensic Science', 'Correctional Administration']::text[], array['Clear path to PNP and public safety careers', 'Licensure profession', 'Strong sense of public service']::text[], array['Physically demanding training', 'Risk inherent to law enforcement work', 'Rank-based salary progression']::text[]),
  ('bs-elementary-education', 'BS in Elementary Education', 'Bachelor', 'Education', 'SAE', 'Prepares future elementary school teachers with foundations in pedagogy and child development.', array['Child and Adolescent Development', 'Principles of Teaching', 'Curriculum Development', 'Educational Technology', 'Practice Teaching']::text[], array['Stable public-sector demand', 'LET licensure gives security of tenure', 'Direct positive impact on children']::text[], array['Modest starting salaries', 'Licensure exam required', 'Large class sizes in public schools']::text[]),
  ('bs-entrepreneurship', 'BS in Entrepreneurship', 'Bachelor', 'Business', 'EAS', 'Builds the skills to start and grow a business, with students often launching real ventures before graduating.', array['Opportunity Seeking', 'Business Plan Development', 'Innovation Management', 'Financial Literacy', 'Digital Marketing']::text[], array['You build your own venture in school', 'Skills transfer to any business role', 'Growing startup and MSME support ecosystem']::text[], array['Income uncertainty as a founder', 'Requires high self-discipline', 'Family capital often assumed']::text[]),
  ('bs-hospitality-management', 'BS in Hospitality Management', 'Bachelor', 'Service', 'ESC', 'Prepares students for hotel, restaurant, and events management with strong practicum components.', array['Food and Beverage Operations', 'Front Office Management', 'Events Management', 'Culinary Fundamentals', 'Tourism and Hospitality Marketing']::text[], array['Clark and tourism corridor create local jobs', 'International placement opportunities', 'People-centered']::text[], array['dynamic work']::text[]),
  ('bs-information-technology', 'BS in Information Technology', 'Bachelor', 'Computing', 'ICR', 'Centers on applying computing systems to business needs: networks, databases, and systems administration.', array['Networking Fundamentals', 'Database Management', 'Web Systems', 'Information Assurance', 'Systems Integration']::text[], array['Broad entry-level opportunities in BPO and IT firms', 'Practical hands-on skills', 'Certifications can substitute for experience']::text[], array['Entry-level roles can start with support work', 'On-call duties for system issues', 'Requires continuous certification']::text[]),
  ('bs-multimedia-arts', 'BS in Multimedia Arts', 'Bachelor', 'Design', 'AES', 'Covers graphic design, animation, video production, and interactive media.', array['Design Fundamentals', 'Digital Illustration', 'Motion Graphics', 'Video Production', 'Interactive Media']::text[], array['Portfolio matters more than grades', 'Freelance and remote-friendly', 'Creative industries are growing']::text[], array['Income can be irregular early on', 'Client revisions test patience', 'Requires self-marketing']::text[]),
  ('bs-nursing', 'BS in Nursing', 'Bachelor', 'Health Sciences', 'SIA', 'Prepares students to become licensed nurses through classroom instruction and intensive hospital duty.', array['Anatomy and Physiology', 'Fundamentals of Nursing', 'Pharmacology', 'Community Health Nursing', 'Medical-Surgical Nursing']::text[], array['High demand locally and abroad', 'Clear licensure path (PNLE)', 'Deeply meaningful patient-facing work']::text[], array['Physically and emotionally demanding', 'Shift work including nights and holidays', 'Board exam pressure']::text[]),
  ('bs-psychology', 'BS in Psychology', 'Bachelor', 'Social Sciences', 'ISA', 'Studies human behavior and mental processes; a common pre-med and HR pathway.', array['General Psychology', 'Experimental Psychology', 'Abnormal Psychology', 'Psychological Assessment', 'Industrial-Organizational Psychology']::text[], array['Flexible pathways: HR']::text[], array['clinical']::text[]),
  ('bs-secondary-education', 'BS in Secondary Education', 'Bachelor', 'Education', 'SEA', 'Prepares high school teachers with a chosen subject specialization such as math, science, or English.', array['Facilitating Learning', 'Assessment of Learning', 'Specialization Courses', 'Educational Technology', 'Practice Teaching']::text[], array['Clear licensure path (LET)', 'Subject specialization deepens expertise', 'Strong demand for STEM teachers']::text[], array['Modest starting salaries', 'Classroom management is demanding', 'Paperwork load']::text[]),
  ('bs-tourism-management', 'BS in Tourism Management', 'Bachelor', 'Service', 'ECS', 'Focuses on travel operations, destination marketing, and tour management.', array['Tourism Planning', 'Travel Agency Operations', 'Destination Marketing', 'Airline Operations', 'Ecotourism']::text[], array['Growing Philippine tourism industry', 'Travel exposure', 'Strong communication skill building']::text[], array['Seasonal employment swings', 'Often starts in frontline roles', 'Industry sensitive to global events']::text[]);
