  ('holy-angel-university', 'Holy Angel University', 'Angeles City', 'Pampanga', 'private', 'Large private Catholic university in Angeles City offering programs in engineering, business, nursing, and the arts.', 'https://www.hau.edu.ph', 'https://www.hau.edu.ph'),
  ('neust', 'Nueva Ecija University of Science and Technology', 'Cabanatuan City', 'Nueva Ecija', 'public', 'State university in Nueva Ecija focused on science, technology, engineering, and teacher education.', 'https://neust.edu.ph', 'https://neust.edu.ph'),
