  ('pup-santa-maria', 'Polytechnic University of the Philippines - Santa Maria Campus', 'Santa Maria', 'Bulacan', 'public', 'Bulacan branch campus of PUP offering accountancy, business, and information technology programs.', 'https://www.pup.edu.ph', 'https://www.pup.edu.ph'),
  ('tarlac-state-university', 'Tarlac State University', 'Tarlac City', 'Tarlac', 'public', 'State university in Tarlac City offering engineering, education, business, and criminology programs.', 'https://tsu.edu.ph', 'https://tsu.edu.ph'),
